v_status VARCHAR2(60);
BEGIN
IF AD_isTriggerEnabled()='N' THEN RETURN; END IF;
If(DELETING) THEN Select status Into v_status from ssccr_pos_card_rec where ssccr_pos_card_rec_id = :OLD.ssccr_pos_card_rec_id; If(v_status = 'RE')Then RAISE_APPLICATION_ERROR(-20000, 'No puedes eliminar una trasacción procesada.'); END IF; END IF;
-- Summary Nodes first EXCEPTION WHEN NO_DATA_FOUND THEN RAISE_APPLICATION_ERROR(-20000, '@20001@') ; END SSCCR_PROCESSED_TRG
